// ============================================================
// CONFIGURATION - A REMPLIR AVANT PREMIER LANCEMENT
// ============================================================
// META_ACCESS_TOKEN : Business Manager > Utilisateurs système
//   Droits requis: ads_read, pages_read_engagement, instagram_basic, ads_management
//   URL: business.facebook.com > Paramètres > Utilisateurs système
//
// DEEPSEEK_API_KEY : platform.deepseek.com > API Keys
//   (A remplacer par ANTHROPIC_API_KEY quand disponible)
//
// WHATSAPP_PHONE_NUMBER_ID : Meta Business > WhatsApp > Configuration API > ID du numero de telephone
// WHATSAPP_RECIPIENT : numero destinataire format international sans + (ex: 33612345678)
//
// Pour chaque ville:
//   ad_account_id : Gestionnaire de publicités > Menu déroulant en haut (format act_XXXXXXXXXX)
//   page_id       : Page Facebook > A propos > Identifiant de la page
//   ig_user_id    : Graph API Explorer > /{page-id}?fields=instagram_business_account
//                   ou null si pas de compte IG lié
// ============================================================

const TOKEN = $env.META_ACCESS_TOKEN || 'REMPLACER_PAR_TOKEN_META';
// Pour passer a Anthropic plus tard: remplacer l URL dans le noeud IA et le model
const AI_KEY = $env.DEEPSEEK_API_KEY || 'REMPLACER_PAR_CLE_DEEPSEEK';
const WA_PHONE_ID  = $env.WA_PHONE_NUMBER_ID || 'REMPLACER_PAR_PHONE_NUMBER_ID';
const WA_RECIPIENT = $env.WA_RECIPIENT || 'REMPLACER_PAR_NUMERO_DEST'; // ex: 33612345678

// Plage de dates: last_7d | last_14d | last_30d | last_90d | this_month | last_month
const DATE_PRESET = 'last_30d';

return [{
  json: {
    token: TOKEN,
    ai_key: AI_KEY,
    wa_phone_id: WA_PHONE_ID,
    wa_recipient: WA_RECIPIENT,
    date_preset: DATE_PRESET,
    villes: [
      {
        nom: 'Metz',
        ad_account_id: 'act_XXXXXXXXXX',
        page_id: 'XXXXXXXXXX',
        ig_user_id: null,
        budget_alloue: 5000,
        objectif_principal: 'Ventes de billets',
        date_evenement: '2025-07-12'
      },
      {
        nom: 'Bordeaux',
        ad_account_id: 'act_XXXXXXXXXX',
        page_id: 'XXXXXXXXXX',
        ig_user_id: null,
        budget_alloue: 5000,
        objectif_principal: 'Ventes de billets',
        date_evenement: '2025-08-23'
      },
      {
        nom: 'Evreux',
        ad_account_id: 'act_XXXXXXXXXX',
        page_id: 'XXXXXXXXXX',
        ig_user_id: null,
        budget_alloue: 4000,
        objectif_principal: 'Notoriete',
        date_evenement: '2025-09-14'
      },
      {
        nom: 'Nevers',
        ad_account_id: 'act_XXXXXXXXXX',
        page_id: null,
        ig_user_id: 'XXXXXXXXXX',
        budget_alloue: 3000,
        objectif_principal: 'Notoriete',
        date_evenement: '2025-10-05'
      }
    ]
  }
}];

const config = $input.first().json;
const { token, villes, date_preset } = config;
const BASE = 'https://graph.facebook.com/v21.0';

const get = async (url) => {
  const r = await fetch(url);
  const d = await r.json();
  if (d.error) { console.warn('Meta API:', d.error.message); return null; }
  return d;
};

// Score de performance: CTR 40% + reach/euro 30% + taux engagement 30%
const scoreAd = (impressions, reach, clicks, spend, actions) => {
  if (impressions < 100) return 0;
  const ctr = impressions > 0 ? clicks / impressions * 100 : 0;
  const engagements = parseInt(actions?.find(a => a.action_type === 'post_engagement')?.value || 0);
  const engRate = reach > 0 ? engagements / reach * 100 : 0;
  const reachPerEuro = spend > 0 ? reach / spend : 0;
  const ctrScore   = Math.min(100, ctr * 20);           // CTR 5% = 100pts
  const reachScore = Math.min(100, reachPerEuro / 5);   // 500 reach/€ = 100pts
  const engScore   = Math.min(100, engRate * 10);       // 10% engagement = 100pts
  return Math.round(ctrScore * 0.40 + reachScore * 0.30 + engScore * 0.30);
};

const getReco = (score) => {
  if (score >= 70) return { label: 'Booster', color: '#16a34a', bg: '#f0fdf4', emoji: '🚀' };
  if (score >= 50) return { label: 'Maintenir', color: '#2563eb', bg: '#eff6ff', emoji: '✅' };
  if (score >= 30) return { label: 'Optimiser', color: '#d97706', bg: '#fffbeb', emoji: '⚠️' };
  return { label: 'Stopper', color: '#dc2626', bg: '#fef2f2', emoji: '🛑' };
};

const results = [];

for (const ville of villes) {
  const out = {
    ville: ville.nom,
    budget_alloue: ville.budget_alloue,
    objectif: ville.objectif_principal,
    date_evenement: ville.date_evenement,
    campaigns: [],
    ads: [],
    audience: { fb: null, ig: null },
    totals: { impressions: 0, reach: 0, clicks: 0, spend: 0, engagements: 0, ctr: '0.00' }
  };

  try {
    // 1. Vue campagnes
    const campUrl = `${BASE}/${ville.ad_account_id}/insights?fields=campaign_name,campaign_id,impressions,reach,clicks,actions,spend,frequency,cpm,cpc,ctr&level=campaign&date_preset=${date_preset}&limit=50&access_token=${token}`;
    const campData = await get(campUrl);
    if (campData?.data) {
      out.campaigns = campData.data.map(c => ({
        id: c.campaign_id,
        nom: c.campaign_name,
        impressions: parseInt(c.impressions) || 0,
        reach: parseInt(c.reach) || 0,
        clicks: parseInt(c.clicks) || 0,
        spend: parseFloat(c.spend) || 0,
        ctr: parseFloat(c.ctr || 0).toFixed(2),
        cpm: parseFloat(c.cpm || 0).toFixed(2),
        frequency: parseFloat(c.frequency || 0).toFixed(1)
      })).sort((a, b) => b.impressions - a.impressions);
    }

    // 2. Vue annonces individuelles (= posts sponsorisés)
    const adInsUrl = `${BASE}/${ville.ad_account_id}/insights?fields=ad_id,ad_name,adset_name,campaign_name,impressions,reach,clicks,actions,spend,frequency,cpm,cpc,ctr,cost_per_action_type&level=ad&date_preset=${date_preset}&limit=100&access_token=${token}`;
    const adInsData = await get(adInsUrl);

    // 3. Détails créatifs (visuels, textes)
    let creatives = {};
    const adsUrl = `${BASE}/${ville.ad_account_id}/ads?fields=id,name,status,creative{id,title,body,image_url,thumbnail_url,call_to_action_type}&limit=100&access_token=${token}`;
    const adsData = await get(adsUrl);
    if (adsData?.data) {
      for (const ad of adsData.data) {
        creatives[ad.id] = {
          titre: ad.creative?.title || null,
          corps: ad.creative?.body ? ad.creative.body.substring(0, 150) : null,
          imageUrl: ad.creative?.image_url || ad.creative?.thumbnail_url || null,
          cta: ad.creative?.call_to_action_type || null,
          statut: ad.status || 'UNKNOWN'
        };
      }
    }

    if (adInsData?.data) {
      out.ads = adInsData.data.map(a => {
        const actions = a.actions || [];
        const imp   = parseInt(a.impressions) || 0;
        const reach = parseInt(a.reach) || 0;
        const clicks = parseInt(a.clicks) || 0;
        const spend = parseFloat(a.spend) || 0;
        const eng   = parseInt(actions.find(x => x.action_type === 'post_engagement')?.value || 0);
        const likes = parseInt(actions.find(x => x.action_type === 'like')?.value || 0);
        const comms = parseInt(actions.find(x => x.action_type === 'comment')?.value || 0);
        const shares= parseInt(actions.find(x => x.action_type === 'post')?.value || 0);
        const videoViews = parseInt(actions.find(x => x.action_type === 'video_view')?.value || 0);
        const linkClicks = parseInt(actions.find(x => x.action_type === 'link_click')?.value || 0);
        const ctr  = parseFloat(a.ctr || 0);
        const score = scoreAd(imp, reach, clicks, spend, actions);
        const reco  = getReco(score);
        const cr    = creatives[a.ad_id] || {};

        return {
          id: a.ad_id,
          nom: a.ad_name || '(sans nom)',
          adset: a.adset_name || '',
          campagne: a.campaign_name || '',
          impressions: imp,
          reach,
          clicks,
          spend,
          engagements: eng,
          likes, comms, shares, videoViews, linkClicks,
          ctr: ctr.toFixed(2),
          cpm: parseFloat(a.cpm || 0).toFixed(2),
          cpc: parseFloat(a.cpc || 0).toFixed(2),
          frequency: parseFloat(a.frequency || 0).toFixed(1),
          costPerEngagement: eng > 0 ? (spend / eng).toFixed(2) : null,
          score,
          reco,
          titre: cr.titre,
          corps: cr.corps,
          imageUrl: cr.imageUrl,
          cta: cr.cta,
          statut: cr.statut
        };
      }).sort((a, b) => b.score - a.score);
    }

    // 4. Audience page/IG
    if (ville.page_id) {
      const pageData = await get(`${BASE}/${ville.page_id}?fields=followers_count,instagram_business_account{followers_count}&access_token=${token}`);
      if (pageData) {
        out.audience.fb = pageData.followers_count ?? null;
        out.audience.ig = pageData.instagram_business_account?.followers_count ?? null;
      }
    } else if (ville.ig_user_id) {
      const igData = await get(`${BASE}/${ville.ig_user_id}?fields=followers_count&access_token=${token}`);
      if (igData) out.audience.ig = igData.followers_count ?? null;
    }

    // 5. Totaux
    const totalImp  = out.ads.reduce((s, a) => s + a.impressions, 0);
    const totalReach= out.ads.reduce((s, a) => s + a.reach, 0);
    const totalClk  = out.ads.reduce((s, a) => s + a.clicks, 0);
    const totalSpd  = out.ads.reduce((s, a) => s + a.spend, 0);
    const totalEng  = out.ads.reduce((s, a) => s + a.engagements, 0);
    out.totals = {
      impressions: totalImp,
      reach: totalReach,
      clicks: totalClk,
      spend: totalSpd,
      engagements: totalEng,
      ctr: totalImp > 0 ? (totalClk / totalImp * 100).toFixed(2) : '0.00',
      engagementRate: totalReach > 0 ? (totalEng / totalReach * 100).toFixed(2) : '0.00',
      cpm: totalImp > 0 ? (totalSpd / totalImp * 1000).toFixed(2) : '0.00',
      budgetRestant: ville.budget_alloue - totalSpd,
      tauxDepense: ville.budget_alloue > 0 ? (totalSpd / ville.budget_alloue * 100).toFixed(1) : '0.0'
    };

  } catch (e) {
    console.error(`Erreur ${ville.nom}:`, e.message);
    out.error = e.message;
  }

  results.push(out);
}

return results.map(r => ({ json: r }));

const villes = $input.all().map(i => i.json);
const cfg = $('Configuration').first().json;

const fmt = n => n != null ? Number(n).toLocaleString('fr-FR') : 'N/A';
const fmtE = n => n != null ? `${Number(n).toFixed(2)} €` : 'N/A';

let prompt = `Tu es un expert en marketing digital spécialisé dans les événements culturels (festivals anime/manga) et la publicité Meta Ads en France.\n\n`;
prompt += `Contexte: Japan Otaku Festival (JOF) et Japan Manga Wave (JMW) - festivals manga/anime itinérants en France.\n`;
prompt += `Objectif: Analyser les performances publicitaires Meta sur ${cfg.date_preset === 'last_30d' ? '30 derniers jours' : cfg.date_preset} et fournir des recommandations précises.\n\n`;

prompt += `=== DONNÉES PAR VILLE ===\n\n`;

for (const v of villes) {
  if (v.error) {
    prompt += `${v.ville}: ERREUR - ${v.error}\n\n`;
    continue;
  }
  const daysUntilEvent = v.date_evenement ? Math.ceil((new Date(v.date_evenement) - new Date()) / 86400000) : null;

  prompt += `--- ${v.ville.toUpperCase()} ---\n`;
  if (daysUntilEvent !== null) prompt += `📅 Événement dans ${daysUntilEvent} jours (${v.date_evenement})\n`;
  prompt += `🎯 Objectif: ${v.objectif || 'N/A'}\n`;
  prompt += `💰 Budget: ${fmtE(v.totals.spend)} dépensé / ${fmtE(v.budget_alloue)} alloué (${v.totals.tauxDepense}%)\n`;
  prompt += `👥 Audience: Facebook ${fmt(v.audience.fb)} abonnés | Instagram ${v.audience.ig != null ? fmt(v.audience.ig) : 'Pas de compte'}\n`;
  prompt += `📊 Performances globales:\n`;
  prompt += `   - Impressions: ${fmt(v.totals.impressions)} | Couverture: ${fmt(v.totals.reach)}\n`;
  prompt += `   - Clics: ${fmt(v.totals.clicks)} | CTR moyen: ${v.totals.ctr}%\n`;
  prompt += `   - Engagements: ${fmt(v.totals.engagements)} | Taux engagement: ${v.totals.engagementRate}%\n`;
  prompt += `   - CPM: ${v.totals.cpm} € | Budget restant: ${fmtE(v.totals.budgetRestant)}\n\n`;

  const topAds = (v.ads || []).slice(0, 5);
  const bottomAds = (v.ads || []).filter(a => a.impressions > 200).slice(-3);

  if (topAds.length > 0) {
    prompt += `🏆 TOP ${topAds.length} ANNONCES (meilleures performances):\n`;
    for (const ad of topAds) {
      prompt += `  • [Score ${ad.score}/100] "${ad.nom}"\n`;
      prompt += `    CTR: ${ad.ctr}% | Reach: ${fmt(ad.reach)} | Engagement: ${fmt(ad.engagements)} | Dépense: ${fmtE(ad.spend)} | CPM: ${ad.cpm}€\n`;
      if (ad.likes || ad.comms || ad.shares) prompt += `    Likes: ${ad.likes} | Commentaires: ${ad.comms} | Partages: ${ad.shares}\n`;
      if (ad.titre) prompt += `    Titre annonce: "${ad.titre}"\n`;
      prompt += `    Recommandation: ${ad.reco.emoji} ${ad.reco.label}\n`;
    }
    prompt += `\n`;
  }

  if (bottomAds.length > 0) {
    prompt += `🔴 ANNONCES LES MOINS PERFORMANTES:\n`;
    for (const ad of bottomAds) {
      prompt += `  • [Score ${ad.score}/100] "${ad.nom}"\n`;
      prompt += `    CTR: ${ad.ctr}% | Reach: ${fmt(ad.reach)} | Dépense: ${fmtE(ad.spend)}\n`;
    }
    prompt += `\n`;
  }

  prompt += `Campagnes actives: ${v.campaigns.length} | Annonces analysées: ${v.ads.length}\n\n`;
}

prompt += `=== DEMANDE D'ANALYSE ===\n\n`;
prompt += `Fournis une analyse structurée en 5 parties:\n\n`;
prompt += `**1. DIAGNOSTIC GLOBAL** (3-4 phrases)\n`;
prompt += `Évaluation générale des performances, villes qui sur/sous-performent, alerte sur les urgences.\n\n`;
prompt += `**2. ANALYSE PAR VILLE** (pour chaque ville avec données):\n`;
prompt += `  - Ce qui fonctionne (annonces à booster)\n`;
prompt += `  - Ce qui doit être stoppé immédiatement (avec raison)\n`;
prompt += `  - Budget: bien utilisé ou sous/sur-dépensé? Que faire?\n`;
prompt += `  - Score de performance global sur 10\n\n`;
prompt += `**3. RECOMMANDATIONS CRÉATIVES** \n`;
prompt += `Types de visuels qui fonctionnent le mieux (images vs vidéos, style graphique), messages/accroches à tester, format publicitaire recommandé pour chaque objectif.\n\n`;
prompt += `**4. CIBLAGES À TESTER**\n`;
prompt += `Audiences à cibler/exclure, géolocalisation, tranches d'âge, centres d'intérêt spécifiques au public anime/manga.\n\n`;
prompt += `**5. PLAN D'ACTION CETTE SEMAINE** (liste priorisée, maximum 7 actions concrètes)\n`;
prompt += `Actions spécifiques avec la ville concernée, l'action exacte et l'impact attendu.\n\n`;
prompt += `Réponds en français, sois concis et très actionnable. Évite les généralités - base-toi sur les données.`;

return [{
  json: {
    prompt,
    villesData: villes,
    ai_key: cfg.ai_key,
    wa_phone_id: cfg.wa_phone_id,
    wa_recipient: cfg.wa_recipient,
    date_preset: cfg.date_preset
  }
}];

const deepseekResp = $input.first().json;
const analyseIA = deepseekResp.choices?.[0]?.message?.content || deepseekResp.error?.message || 'Analyse IA indisponible.';
const aiData = $('Preparer Analyse IA').first().json;
const villes = aiData.villesData || [];
const wa_phone_id  = aiData.wa_phone_id;
const wa_recipient = aiData.wa_recipient;
const dateStr = new Date().toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit', year: 'numeric' });

const fmt  = n => n != null ? Number(n).toLocaleString('fr-FR') : 'N/A';
const fmtE = n => n != null ? `${Number(n).toFixed(2).replace('.', ',')} €` : 'N/A';

const globalTotals = {
  impressions: villes.reduce((s, v) => s + (v.totals?.impressions || 0), 0),
  reach:       villes.reduce((s, v) => s + (v.totals?.reach || 0), 0),
  spend:       villes.reduce((s, v) => s + (v.totals?.spend || 0), 0),
  clicks:      villes.reduce((s, v) => s + (v.totals?.clicks || 0), 0),
  engagements: villes.reduce((s, v) => s + (v.totals?.engagements || 0), 0)
};

let msg = `📊 *Rapport Meta Ads JOF/JMW*\n_${dateStr}_\n\n`;
msg += `*📈 KPI GLOBAUX*\n`;
msg += `👁 ${fmt(globalTotals.impressions)} impressions\n`;
msg += `👥 ${fmt(globalTotals.reach)} personnes touchées\n`;
msg += `🖱 ${fmt(globalTotals.clicks)} clics\n`;
msg += `💬 ${fmt(globalTotals.engagements)} engagements\n`;
msg += `💰 ${fmtE(globalTotals.spend)} dépensés\n`;

for (const v of villes) {
  if (v.error) {
    msg += `\n━━━━━━━━━━\n📍 *${v.ville}* — Erreur: ${v.error}\n`;
    continue;
  }
  const t = v.totals;
  const budgetPct = v.budget_alloue > 0 ? (t.spend / v.budget_alloue * 100).toFixed(1) : '0.0';
  const topAd    = (v.ads || []).find(a => a.score >= 50);
  const bottomAd = (v.ads || []).slice().reverse().find(a => a.score < 30 && a.impressions > 200);

  msg += `\n━━━━━━━━━━\n📍 *${v.ville}* (${v.campaigns.length} camp. • ${v.ads.length} ann.)\n`;
  msg += `💰 ${fmtE(t.spend)} / ${fmtE(v.budget_alloue)} — ${budgetPct}%\n`;
  msg += `👁 ${fmt(t.impressions)} impr | CTR: ${t.ctr}%\n`;
  msg += `👥 ${fmt(t.reach)} reach | Eng: ${t.engagementRate}%\n`;
  if (topAd)    msg += `🚀 Top [${topAd.score}]: "${topAd.nom.substring(0, 38)}"\n`;
  if (bottomAd) msg += `🛑 Stopper [${bottomAd.score}]: "${bottomAd.nom.substring(0, 35)}"\n`;
}

const aiHeader = `\n━━━━━━━━━━\n🤖 *ANALYSE IA*\n`;
const maxAiLen = 4000 - msg.length - aiHeader.length - 30;
const cleanAi = analyseIA
  .replace(/\*\*(.+?)\*\*/g, '*$1*')
  .replace(/^#{1,3}\s+(.+)$/gm, '*$1*')
  .trim();
const truncatedAi = cleanAi.length > maxAiLen
  ? cleanAi.substring(0, maxAiLen) + '...\n_(analyse tronquée)_'
  : cleanAi;

msg += aiHeader + truncatedAi;

if (msg.length > 4096) {
  msg = msg.substring(0, 4060) + '\n...\n_(rapport tronqué)_';
}

return [{ json: { text: msg, wa_phone_id, wa_recipient } }];
